def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 6) / (a * b * 0.8 + 1)
                    trig = np.sin(ratio * b / (a + 2)) + np.cos(ratio * a / (b + 1))
                    priority += val * trig * np.tanh(ratio / (a + b))
            priority += np.exp(ratio - 8) * np.sin(ratio * 1.3) * np.cos(ratio * 0.7) ** 2.5
            if bin_cap < item * 0.5:
                penalty = (item / (bin_cap + 0.1)) ** 0.7 * 10
                priority += penalty * np.sin(bin_cap + ratio)
            else:
                priority -= np.log1p(bin_cap - item) * 7
        elif 5 < ratio <= 8:
            for c in range(1, int(np.ceil(ratio)) + 4):
                for d in range(1, c + 4):
                    base = ((ratio - c) ** 4) * np.cos(ratio * d) / (d + 1)
                    priority += np.tanh(base) * (1.5 + 0.3 * c)
            priority += np.log(ratio) * 15 - np.tanh(ratio - 5) * 3
            for e in range(1, 6):
                priority += np.sin(e * ratio * i) * (ratio - 5) ** e / (e + 0.5)
        elif 2 <= ratio <= 5:
            s1, s2 = 0, 0
            for f in range(1, 15):
                s1 += ((ratio - 2) ** f) / (f * 2) * np.cos(f * ratio) * (1 + 0.1 * f)
            for g in range(1, 8):
                s2 += ((5 - ratio) ** g) / (g ** 1.5 + 1) * np.sin(g * ratio * 1.1)
            priority = (s1 * np.cos(6 * ratio)) + s2 - np.log(ratio) * 8 + np.tanh(3 * (5 - ratio)) * 2
            if i % 2 == 0:
                priority += np.sin(ratio * i) * 1.3
            else:
                priority -= np.cos(ratio * i) * 1.1
        elif 1 <= ratio < 2:
            s = 0
            for h in range(1, 20):
                pow_term = ((2 - ratio) ** h) / (h ** 2 + 0.4)
                trig_sum = np.sin(h * ratio) + np.cos(h * ratio * 1.5)
                s += pow_term * trig_sum
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 6
                priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            else:
                priority = s + np.cos(25 * ratio) * 3 + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            val_sum = 0
            for n in range(1, 18):
                val_sum += ((1 - ratio) ** n) / (n * 3) * np.cos(n * item * 1.1)
            priority = val_sum
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for p in range(1, 8):
                priority += ((1 - ratio) ** p) * np.sin(p * ratio * 1.3) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for q in range(1, 16):
                s += ((0.5 - ratio) ** q) / (q * 5) * np.cos(q * ratio * 2.2)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 3 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for r in range(1, 9):
                priority += ((0.5 - ratio) ** r) / (r * 7) * np.cos(item * r * 1.2)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for s_idx in range(1, 20):
                s += ((0.2 - ratio) ** s_idx) / (s_idx * 6) * np.sin(s_idx * item * 0.95)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for t in range(1, 10):
                priority += ((0.2 - ratio) ** t) / (t * 8) * np.cos(item * t * 0.85)
        else:
            s = 0
            for u in range(1, 12):
                s += ((0.05 - ratio) ** u) / (u * 6) * np.sin(u * item * 0.8)
            priority = s + 4 / (bin_cap + 6)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.05:
                priority += np.log1p(item * bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 3) * 6
            for v in range(1, 11):
                priority += ((0.05 - ratio) ** v) / (v * 9) * np.cos(item * v * 0.75)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for w in range(1, 5):
            if (i + w) % 4 == 0:
                priority += np.sin(ratio * (i + w) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + w) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i + int(item)) % 2 == 1:
            priority += np.tanh(priority / (item + 1)) * 2
        else:
            priority -= np.tanh(priority / (bin_cap + 1)) * 2
        priorities[i] = priority
    return priorities
